    local designHeight = DESIGN_SCREEN_SIZE.Height
    local safeArea = Screen.safeArea
    local screenHeight = Screen.height
    local fvo = self._virtualCamBattle.m_Lens.FieldOfView
    self._orgBattleFOV = fvo
    --local tanY = self._mapRoot2D.transform.localPosition.z
    --MapRoot2D从在vCamBattleGo坐标Z是80
    --local tanY = 80
    --local tanX = math.tan(math.angle2radian(0.5 * fvo)) * tanY


    local heightHaft = safeArea.height * designWidth / safeArea.width * 0.5 * 0.01
    --local scale2d = tanX / heightHaft

    local orthographicSize,designOrthographicSize = LxUiHelper.GetCameraSize()
    local scale2d = orthographicSize / designOrthographicSize
    --self._mapRoot2D.transform.localScale = Vector3.New(scale2d, scale2d, scale2d)
    self._mapRoot2D.transform.localScale = Vector3.one

    ---摄象机的orthographicSize 其实是 可见世界坐标高度的一半 scale2d 为世界坐标与屏幕坐标的比值
    self._scale2d = orthographicSize * 2 / screenHeight

    local m_Lens = self._virtualCamBattle.m_Lens
    m_Lens.OrthographicSize = orthographicSize
    self._virtualCamBattle.m_Lens = m_Lens
    self._virtualCamFormation.m_Lens = m_Lens
    self._virtualCamFormation1.m_Lens = m_Lens

    --- 适配VirtualCamFormation的Y轴坐标，(1280,13.5) - (1560, 14.5)
    --local fy = math.lineFunc({x = 1280, y = 14.8}, {x = 1560, y = 15.8}, 2 * heightHaft * 100)
end

function LBattleViewFace:InitFormationRoot(pointTrans)
    local standTrans = pointTrans:Find('Stand')
    local battleStateTrans = pointTrans:Find('BattleState')
    local selTrans,lockTrans,hurtTrans,notSoldTrans,soldTrans, qualityTrans, numTrans
    local qualityObjList = {}
    if standTrans then
        selTrans = standTrans:Find('Sel')
        lockTrans = standTrans:Find('Lock')

        numTrans = standTrans:Find('Num')

        qualityTrans = standTrans:Find('Quality')
        if qualityTrans then
            for i = 1, 8 do
                local quality = qualityTrans:Find("Quality"..tostring(i))
                if quality then
                    qualityObjList[i] = quality.gameObject
                end
            end
        end

    end
    if battleStateTrans then
        hurtTrans = battleStateTrans:Find('Hurt')
        notSoldTrans = battleStateTrans:Find('NotSold')
        soldTrans = battleStateTrans:Find('Sold')
    end
    ---@class V_ViewFace_FormationData
    local result = {
        pointTrans = pointTrans,
        standTrans = standTrans,
        standObj = standTrans and standTrans.gameObject or nil,
        qualityTrans = qualityTrans,
        qualityObj = qualityTrans and qualityTrans.gameObject or nil,
        qualityObjList = qualityObjList,
        qualityKey = 0,
        selTrans = selTrans,
        selObj = selTrans and selTrans.gameObject or nil,
        lockTrans = lockTrans,
        lockObj = lockTrans and lockTrans.gameObject or nil,
        numTrans = numTrans,
        numObj = numTrans and numTrans.gameObject or nil,
        hurtTrans = hurtTrans,
        hurtObj = hurtTrans and hurtTrans.gameObject or nil,
        notSoldTrans = notSoldTrans,
        notSoldObj = notSoldTrans and notSoldTrans.gameObject or nil,
        soldTrans = soldTrans,
        soldObj = soldTrans and soldTrans.gameObject or nil,
        battleStateObj = battleStateTrans and battleStateTrans.gameObject or nil,
    }
    return result
end

