--- 播放镜头抖动
function LBattleViewFace:PlayShake(stepShockTime, x, y)
    local seqTween = self:NewTweenSeq("PlayShake", function()
        self:GetSeqCom():DeleteSeq("PlayShake")
    end)
    local ShakeRoot = self._ShakeRoot
    ShakeRoot.localPosition = Vector3.zero
    local pos = Vector3.zero
    local tweenShake = LxUiHelper.TweenFloat(0, 1, stepShockTime, function(percent)
        local tx, ty = PJXUtil.InsideUnitCircle(0, 0)
        pos.x = tx * x * (1 - percent)
        pos.y = tx * y * (1 - percent)
        ShakeRoot.localPosition = pos
    end)

    seqTween:Append(tweenShake)
    seqTween:SetAutoKill(false)
    seqTween:PlayForward()
end

