function LBattleViewFace:PlayFaceOps(data)
    if self:IsDisposed() then return end
    ---@type LBattleShowFaceEffectItem
    local effectData = data.effectData
    local callback = data.callback
    local opsUnit = data.opsUnit
    local opsType = effectData.opsType
    local orgValue = 1
    if opsType == BattleShowFaceOpsType.Color then
        orgValue = 0
    elseif opsType == BattleShowFaceOpsType.Scale or opsType == BattleShowFaceOpsType.Focus then
        self._isLockFieldOfView = true
    end

    local faceIn = self:NewFaceTween(opsType, orgValue, effectData.opsValue, effectData.opsStr, effectData.fadeInTime, opsUnit, 1)
    local faceOut = self:NewFaceTween(opsType, effectData.opsValue, orgValue, effectData.opsStr, effectData.fadeOutTime, opsUnit, 2)

    local key = self:NewTweenId("PlayFaceOps")
    local tween = self:NewTweenSeq(key, function()
        if self:IsDisposed() then return end
        if opsType == BattleShowFaceOpsType.Scale or opsType == BattleShowFaceOpsType.Focus then
            self._isLockFieldOfView = false
            if self._virtualCamBattle then
                self._virtualCamBattle.transform.localEulerAngles = self._orgBattleEulerAngles
                local camLen = self._virtualCamBattle.m_Lens
                camLen.FieldOfView = self._orgBattleFOV
                self._virtualCamBattle.m_Lens = camLen
            end
        end
        if IsValid(self._mapMask) then
            local color = Color.New(0,0,0, 0)
            self._mapMask.color = color
        end
        if effectData.hideUI and effectData.hideUI > 0 then
            FireEvent(EventNames.BATTLE_SHOW_FACE_UI,{
                show = true
            })
        end
        if callback then callback() end
    end)
    tween:AppendInterval(effectData.startTime)
    tween:AppendCallback(function()
        if self:IsDisposed() then return end
        if effectData.hideUI and effectData.hideUI > 0 then
            FireEvent(EventNames.BATTLE_SHOW_FACE_UI, {
                show = false
            })
        end
    end)
    if type(faceIn) == "function" then
        tween:AppendCallback(faceIn)
    elseif type(faceIn) == "number" then
        tween:AppendInterval(faceIn)
    elseif type(faceIn) == "table" then
        local isAppend = false
        for i, v in ipairs(faceIn) do
            if type(v) == "function" then
                tween:AppendCallback(v)
            elseif type(v) == "number" then
                tween:AppendInterval(v)
                isAppend = true
            else
                if not isAppend then
                    isAppend = true
                    tween:Append(v)
                else
                    tween:Join(v)
                end
            end
        end
    elseif faceIn then
        tween:Append(faceIn)
    end
    tween:AppendInterval(effectData.lifeTime)

    if type(faceOut) == "function" then
        tween:AppendCallback(faceOut)
    elseif type(faceOut) == "number" then
        tween:AppendInterval(faceOut)
    elseif type(faceOut) == "table" then
        local isAppend = false
        for i, v in ipairs(faceOut) do
            if type(v) == "function" then
                tween:AppendCallback(v)
            elseif type(v) == "number" then
                tween:AppendInterval(v)
                isAppend = true
            else
                if not isAppend then
                    isAppend = true
                    tween:Append(v)
                else
                    tween:Join(v)
                end
            end
        end
    elseif faceOut then
        tween:Append(faceOut)
    end
    tween:AppendCallback(function()
        if self:IsDisposed() then return end
        if effectData.hideUI and effectData.hideUI > 0 then
            FireEvent(EventNames.BATTLE_SHOW_FACE_UI,{
                show = true
            })
        end
    end)
    tween:SetAutoKill(true)
    tween:PlayForward()
end

---@param opsUnit LBattleViewUnit
function LBattleViewFace:NewFaceTween(opsType, fromValue, toValue, opsStr, fadeTime, opsUnit, opsIdx)
    local faceItem = nil
    if opsType == BattleShowFaceOpsType.Color then
        if IsValid(self._mapMask) then
            local fromColor = Color.New(0,0,0, fromValue)
            local toColor = Color.New(0,0,0, toValue)
            self._mapMask.color = fromColor
            faceItem = self._mapMask:DOColor(toColor, fadeTime)
        end
    elseif opsType == BattleShowFaceOpsType.Hide then
        local bShow = (toValue == 1)
        faceItem = function()
            if IsValid(self._mapRoot2D) then
                local hideGo = self._mapRoot2D
                if string.isvalid(opsStr) then
                    local childNams = string.split(opsStr, ",")
                    for i, v in ipairs(childNams) do
                        local child = self._mapTrans:Find(v)
                        if child then
                            hideGo = child.gameObject
                            ShowObject(hideGo, bShow)
                        end
                    end
                else
                    ShowObject(hideGo, bShow)
                end

            end
        end
    elseif opsType == BattleShowFaceOpsType.Scale then
        if toValue == 0 then toValue = 1 end
        if fromValue == 0 then fromValue = 1 end
        local fov = self._orgBattleFOV or 27
        local fromFOV = fov / fromValue
        if IsValid(self._virtualCamBattle) then
            local fromLen = self._virtualCamBattle.m_Lens
            fromLen.FieldOfView = fromFOV
            self._virtualCamBattle.m_Lens = fromLen
        end

        local toFOV = fov / toValue
        faceItem = LxUiHelper.TweenFloat(fromFOV, toFOV, fadeTime, function(value)
            if IsValid(self._virtualCamBattle) then
                local toLen = self._virtualCamBattle.m_Lens
                toLen.FieldOfView = value
                self._virtualCamBattle.m_Lens = toLen
            end
        end)
    elseif opsType == BattleShowFaceOpsType.Focus then
        local defineFOV = self._orgBattleFOV or 27
        local fromFOV = defineFOV
        local toFOV = defineFOV
        if IsValid(self._virtualCamBattle) then
            local fromLen = self._virtualCamBattle.m_Lens
            fromFOV = fromLen.FieldOfView
        end

        if toValue ~= 0 then
            toFOV = toFOV / toValue
        end

        if opsUnit == 1 and opsUnit.teamIdx == BattleTeamSide.teamA then
            toFOV = toFOV + 3
        end

        local faceItem1 = LxUiHelper.TweenFloat(fromFOV, toFOV, fadeTime, function(value)
            if IsValid(self._virtualCamBattle) then
                local toLen = self._virtualCamBattle.m_Lens
                toLen.FieldOfView = value
                self._virtualCamBattle.m_Lens = toLen
            end
        end)
        -- 使用opsIdx去区分聚焦步骤
        if opsIdx == 1 then
            local funcItem = function()
                if opsUnit and IsValid(opsUnit:GetModelTrans()) and IsValid(self._virtualCamBattle) then
                    self._virtualCamBattle.LookAt = opsUnit:GetModelTrans()
                end
            end
            faceItem = {funcItem, faceItem1}
        else
            local funcItem = function()
                if IsValid(self._virtualCamBattle) then
                    self._virtualCamBattle.LookAt = nil
                end
            end
            local faceItem2 = nil
            if IsValid(self._virtualCamBattle) then
                local camTrans = self._virtualCamBattle.transform
                faceItem2 = camTrans:DOLocalRotate(self._orgBattleEulerAngles, fadeTime)
            end
            faceItem = {funcItem, faceItem1, faceItem2}
        end
    end
    return faceItem
end

