        if results and results.Length > 0 then
            local length = results.Length
            for i = 1, length do
                local rayResult = results[i-1]
                local obj = rayResult.collider.gameObject
                if obj.name == 'FormationBox' then
                    self._skillUnitList = MgrCenter.BattleMgr:GetSkillViewUnitList(self._skillCastId, rayResult.point, self._dragSkillRefId)
                    if self._skillUnitList then
                        for idx, unit in ipairs(self._skillUnitList) do
