end

function LBattleViewFace:UpdatePoint()
    if not self._unitMgr then return end
    if not self._unitMgr then return end
    local heroPos = nil
    local distance = 999
    local newNode = nil
    local newIndex
    local bFormationB = self._bFormationB
    if self._touchHero then
        heroPos = self._touchHero.transform.position
        local map = bFormationB and self._formationNodeMap2 or self._formationNodeMap1
        for i, node in pairs(map) do
            local newDistance = Vector2.Distance(heroPos, node.position)
            if newDistance < distance then
                distance = newDistance
                newNode = node
                newIndex = i
            end
        end
    end
    local points = bFormationB and self._formation2Points or self._formation1Points
    for index,transInfos in pairs(points) do
        local showSel = false
        if heroPos then
            if Mathf.Clamp(newIndex, 1, BattlePosCount) == index and not ModuleCenter.Battle:IsPosLock(index, self._bFormationB and self._formationIdB or self._formationIdA) then
                showSel = true
            end
        end
        ShowObject(transInfos.selObj,showSel)
    end
end

function LBattleViewFace:OnDragEnd(gesture)
    if self._isFormationMode then
        self:PushDownHero()
        self:UpdatePoint()
    elseif self._isDragSKill then
        local effectIds = {}
        local results = PJXUtil.TouchHitRays(gesture.position, 1, true)
        if results and results.Length > 0 then
            local length = results.Length
            for i = 1, length do
                local rayResult = results[i-1]
                local obj = rayResult.collider.gameObject
                if obj.name == 'FormationBox' then
                    self._skillUnitList = MgrCenter.BattleMgr:GetSkillViewUnitList(self._skillCastId, rayResult.point, self._dragSkillRefId)
                    if self._skillUnitList then
                        for i, unit in ipairs(self._skillUnitList) do
                            table.insert(effectIds, unit.id)
                            unit:SetSel(false)
                        end
                    end
                    self._skillUnitList = nil
                    break
                end
            end
        end
        FireEvent(EventNames.BATTLE_HAND_SKILL_DRAG, {isSel = #effectIds > 0, isDragEnd = true, targetId = self._skillCastId, skillRefId = self._dragSkillRefId, effectIds = effectIds})
    end
end

