function LBattleViewFace:SetTestFormationB(bFormationB)
    self._bFormationB = bFormationB
end

function LBattleViewFace:SetFormationId(formationIdA, formationIdB)
    self._formationIdA = formationIdA
    self._formationIdB = formationIdB
end

function LBattleViewFace:CheckIsDragHero(go)
    if go.transform and go.transform.parent and go.transform.parent.parent then
        local parent = go.transform.parent.parent
        if self._battleConfig.battleType == BattleType.Test and self._bFormationB then
            return parent == self._formationRoot2.transform
        end
        return parent == self._formationRoot1.transform
    end
    return false
end

function LBattleViewFace:OnTouchUp(gesture)
    if self._isFormationMode then
        if not self._touchDrag then
            self:PushDownHero()
            self:CheckTouchLockEnd()
        end
    else

    end
end

function LBattleViewFace:IsEnableChangePos(node)
    if IsNull(node) then
        return false
    end
    local posIdx = tonumber(node.name) or 0
    --目前只移动1-6的单位
    if Mathf.Clamp(posIdx, 1, BattlePosCount) == posIdx then
        return true
    end
    return false
end

function LBattleViewFace:CheckTouchLockStart(go)
    if self._touchLock or IsNull(go) then
        return
    end
    if go.name ~= "Formation1" or go.transform.parent.name ~= "Formation1" then
        local isEnough = false
        if self._battleConfig.battleType == BattleType.Test and (go.name == "Formation2" or go.transform.parent.name == "Formation2") then
            isEnough = true
        end
        if not isEnough then return end
    end
    self._touchLock = go
    go.transform.parent.parent.localScale = Vector3.New(1.05,1.05,1.05)
end

function LBattleViewFace:CheckTouchLockEnd()
    if not self._touchLock or IsNull(self._touchLock) then
        return
    end
    local go = self._touchLock
    go.transform.parent.parent.localScale = Vector3.one
    local posIdx = tonumber(go.transform.parent.parent.name)
    local ref = GameTable.BattleStationRef[posIdx]
    if ref then
        ShowSysMsg(I18nText(ref.openConditionText))
    end
    self._touchLock = nil
end

function LBattleViewFace:PushUpHero(go, startScreenPos)
    if self._touchHero or IsNull(go) then
        return
    end

    if not go.transform or not go.transform.parent or not go.transform.parent.parent then
        local parent = go.transform.parent.parent
        local isEnough = false
        if self._battleConfig.battleType == BattleType.Test and parent == self._formationRoot2.transform and self._bFormationB then
            isEnough = true
        elseif go.transform.parent.parent == self._formationRoot1.transform then
            isEnough = true
        end
        if not isEnough then return end
    end
    self._touchHero = go
    self._heroPosition = go.transform.localPosition
    self._orgNode = go.transform.parent
    self._heroScale = go.transform.localScale
    local touchScale = 1.05
    go.transform.localScale = Vector3.New(touchScale * self._heroScale.x,touchScale * self._heroScale.y,touchScale * self._heroScale.x)
    self._touchHero.transform.localPosition = self._heroPosition
    self._heroPosition = go.transform.position
    local starWorldPos = LxUiHelper.GetSceneCamera():ScreenToWorldPoint(startScreenPos)
    starWorldPos.z = 0
    self._heroPosOffset = self._heroPosition - starWorldPos

    local curPos = tonumber(self._orgNode.name)
    FireEvent(EventNames.FORMATION_PICK_HERO, curPos)
end

function LBattleViewFace:PushDownHero()
    if self._touchHero then
        local heroPos = self._touchHero.transform.position
        local orgNode = self._orgNode
        local distance = 999
        local newNode = nil
        local tempMap = self._bFormationB and self._formationNodeMap2 or self._formationNodeMap1
        for i, node in pairs(tempMap) do
            local newDistance = Vector2.Distance(heroPos, node.position)
            if newDistance < distance then
                distance = newDistance
                newNode = node
            end
        end

        local curPos = tonumber(orgNode.name)
        FireEvent(EventNames.FORMATION_DOWN_HERO, curPos)
        local desPos = 0
        --- 移动距离大于2，代表删除角色
        if distance > 2 or not newNode then
            desPos = -1
        else
            desPos = tonumber(newNode.name)
            --- 换位区域限制
            if Mathf.Clamp(curPos, 1, BattlePosCount) == curPos and Mathf.Clamp(desPos, 1, BattlePosCount) ~= desPos then
                --if desPos == 8 then
                --    desPos = curPos
                --else
                    desPos = -1
                --end
            --elseif Mathf.Clamp(curPos, 7, 9) == curPos and Mathf.Clamp(desPos, 7, 9) ~= desPos then
            --    desPos = curPos
            end
        end
        local setPosIdx = 0
        self._touchHero.transform.localScale = self._heroScale
        if curPos == desPos then
            setPosIdx = curPos
            self._touchHero.transform.localPosition = Vector3.zero
            if self._isClickMode then
                FireEvent(EventNames.FORMATION_CLICK_POS, {clickPos = curPos})
            end
        else
            if ModuleCenter.Battle:IsPosLock(desPos, self._bFormationB and self._formationIdB or self._formationIdA) then
                setPosIdx = curPos
                self._touchHero.transform.localPosition = Vector3.zero
            else
                self._touchHero.transform.localPosition = Vector3.zero
                FireEvent(EventNames.FORMATION_CHANGE_POS, {curPos = curPos, desPos = desPos})
            end
        end
        if not self._isClickMode then
            FireEvent(EventNames.FORMATION_DRAG_HERO_END, setPosIdx)
        end
    end
    self._heroPosition = nil
    self._touchHero = nil
end

function LBattleViewFace:ChangeFormationState(data)
    ---@type LBattleViewUnit
    local atkUnit = data.atkUnit

    ---@type table<number,LBattleViewUnit>
    local collectAtkMap = {}
    collectAtkMap[atkUnit.index] = atkUnit

    ---@type table<number,LBattleViewUnit>
    local collectTargetMap = {}

    ---@type LBattleViewUnit
    local targetUnit = data.targetUnit
    if targetUnit then
        collectTargetMap[targetUnit.index] = targetUnit
    end

    ---@type LBattleViewUnit[]
    local targetUnitList = data.targetUnitList
    if targetUnitList and #targetUnitList > 0 then
        for k,v in pairs(targetUnitList) do
            collectTargetMap[v.index] = v
        end
    end

    local atkTeamIdx = atkUnit:GetTeamIndex()
    local targetTeamIdx = atkUnit:GetEnemyTeamIdx()

    local state = data.state
    if state == 1 then
        self:SetFormationHeroStandState(collectAtkMap, atkTeamIdx,true)
        self:SetFormationHeroStandState(collectTargetMap, targetTeamIdx,false)
    elseif state == 2 then
        self:SetFormationEndState(collectAtkMap,atkTeamIdx)
        self:SetFormationEndState(collectTargetMap,targetTeamIdx)
    end
end

---@param viewUnitMap table<number,LBattleViewUnit>
function LBattleViewFace:SetFormationHeroStandState(viewUnitMap,teamIdx,isAtk)
    local formationPoints = self:GetFormationData(teamIdx)
    for k,v in pairs(formationPoints) do
        if viewUnitMap[k] then
            if isAtk then
                ShowObject(v.soldObj,true)
            else
                ShowObject(v.hurtObj,true)
            end
            ShowObject(v.notSoldObj,false)
        end
    end
end

function LBattleViewFace:SetFormationEndState(viewUnitMap,teamIdx)
    local formationPoints = self:GetFormationData(teamIdx)
    for k,v in pairs(formationPoints) do
        if viewUnitMap[k] then
            ShowObject(v.notSoldObj,true)
            ShowObject(v.soldObj,false)
            ShowObject(v.hurtObj,false)
        end
    end
end

function LBattleViewFace:GetFormationData(teamIdx)
    if teamIdx == BattleTeamSide.teamA then
        return self._formation1Points
    else
        return self._formation2Points
    end
end

return LBattleViewFace